-- Create "processes" table
CREATE TABLE "processes" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "code" character varying NOT NULL,
  "name" character varying NOT NULL,
  "category" character varying NULL,
  "outsourcing_enabled" boolean NOT NULL DEFAULT false,
  "inhouse_enabled" boolean NOT NULL DEFAULT true,
  "quality_required" boolean NOT NULL DEFAULT false,
  "sort_order" bigint NOT NULL DEFAULT 0,
  "note" character varying NULL,
  "is_active" boolean NOT NULL DEFAULT true,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "processes_sort_order_non_negative" CHECK (sort_order >= 0)
);
-- Create index "process_category" to table: "processes"
CREATE INDEX "process_category" ON "processes" ("category");
-- Create index "process_code" to table: "processes"
CREATE UNIQUE INDEX "process_code" ON "processes" ("code");
-- Create index "process_inhouse_enabled" to table: "processes"
CREATE INDEX "process_inhouse_enabled" ON "processes" ("inhouse_enabled");
-- Create index "process_is_active" to table: "processes"
CREATE INDEX "process_is_active" ON "processes" ("is_active");
-- Create index "process_outsourcing_enabled" to table: "processes"
CREATE INDEX "process_outsourcing_enabled" ON "processes" ("outsourcing_enabled");
-- Create index "process_sort_order_id" to table: "processes"
CREATE INDEX "process_sort_order_id" ON "processes" ("sort_order", "id");
